PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?chamberLabel WHERE {
  VALUES ?chamber {
    wd:Q3511459 wd:Q2682658
  }
  ?chamber rdfs:label ?chamberLabel .
  FILTER(LANG(?chamberLabel) = "en")
  FILTER NOT EXISTS {
    ?chamber wdt:P2243 ?termLimit
  }
}

